@import models.Post
@(post: Post)

@main("Blog Post") {
  <article class="post">
    <header>
      <h1>@post.title</h1>
      <p class="meta">Posted by @post.author on @post.publishedDate</p>
    </header>
    <div class="content">
      @Html(post.content)
    </div>
  </article>
}